const text = $input.first().json.body?.text || $input.first().json.text || '';

if (!text) {
  throw new Error('No text provided in request body');
}

const prompt = `You are a legal document parser for Florida insurance defense cases. Extract the following information from this email requesting production of documents, and return it as JSON.

This is a Motion to Compel Documentation Relied Upon. The lawyer took a deposition where a witness testified that the defendant relied on certain documents for their coverage decision. Now the lawyer wants those documents produced.

Do NOT invent or hallucinate any information. If a field is unclear or missing, return null for that field.

DOCUMENT TEXT:
${text}

RETURN ONLY VALID JSON — no markdown, no explanation, no code blocks. Just the raw JSON object:

{
  "plaintiffNames": ["PLAINTIFF FULL NAME IN ALL CAPS"],
  "defendantName": "DEFENDANT FULL NAME IN ALL CAPS",
  "caseNumber": "case number string",
  "circuitNumber": "e.g. 15th",
  "county": "COUNTY NAME IN ALL CAPS",
  "deponentName": "Full name of person who was deposed",
  "deponentTitle": "Their role e.g. Corporate Representative, Desk Adjuster, Field Adjuster, Claims Manager",
  "deponentPronoun": "he or she or they",
  "depositionDate": "Spelled out date e.g. September 22, 2025",
  "documentRequests": [
    {
      "whatTestified": "What the deponent testified the defendant relied on — e.g. its Field Adjuster's unredacted narrative report in support of its affirmative defenses and coverage decision",
      "whatRequested": "What document the plaintiff is requesting — e.g. Defendant's Field Adjuster's unredacted narrative report which was relied upon in support of its affirmative defenses and to determine coverage for this claim"
    }
  ]
}

EXTRACTION RULES:
- plaintiffNames: ALL plaintiff names in ALL CAPS. If multiple joined by AND, split into separate array entries.
- defendantName: Usually an insurance company. ALL CAPS.
- caseNumber: The civil case number.
- circuitNumber: The judicial circuit number e.g. 11th, 15th, 17th.
- county: County name in ALL CAPS.
- deponentName: The person whose deposition was taken. Could be ANY role — Corporate Representative, Desk Adjuster, Field Adjuster, Claims Reviewer, Supervisor, etc.
- deponentTitle: Their exact title/role as described in the email.
- deponentPronoun: he/she/they based on context.
- depositionDate: When the deposition took place. Spelled out fully.
- documentRequests: One entry per SEPARATE document type being requested. Each email may request multiple different documents from the same deposition testimony.
  - whatTestified: The testimony about what the defendant relied on (for paragraph 3 of the motion)
  - whatRequested: The specific document being requested (for paragraph 4 of the motion)
- Dates must be spelled out: September 22, 2025 — NOT 09/22/2025.
- Keep the phrasing close to what the lawyer wrote — do not rephrase or summarize.`;

return [{
  json: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 2048,
    messages: [
      {
        role: 'user',
        content: prompt
      }
    ]
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '';

if (!content) {
  throw new Error('Empty response from Claude API');
}

let parsed;
try {
  const clean = content
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error('Failed to parse AI response as JSON. Raw response: ' + content.substring(0, 300));
}

if (!parsed.plaintiffNames || !Array.isArray(parsed.plaintiffNames) || parsed.plaintiffNames.length === 0) {
  throw new Error('No plaintiff names found in document');
}
if (!parsed.documentRequests || !Array.isArray(parsed.documentRequests) || parsed.documentRequests.length === 0) {
  throw new Error('No document requests found in document');
}

parsed.deponentPronoun = ['he', 'she', 'they'].includes(parsed.deponentPronoun) ? parsed.deponentPronoun : 'they';

return [{ json: parsed }];
